class Solution:
    def minCost(self, s, encCost, flatCost):
        # independent construction: plain recursion over string slices (recomputing counts
        # with str.count each call) rather than the prefix-sum + index-pair memoization
        # the optimal solution uses.
        def rec(sub):
            length = len(sub)
            ones = sub.count('1')
            best = flatCost if ones == 0 else length * ones * encCost
            if length % 2 == 0 and length > 0:
                mid = length // 2
                best = min(best, rec(sub[:mid]) + rec(sub[mid:]))
            return best
        return rec(s)

