class Solution:
    def minCost(self, s, encCost, flatCost):
        n = len(s)
        prefix = [0] * (n + 1)
        for i, ch in enumerate(s):
            prefix[i + 1] = prefix[i] + (1 if ch == '1' else 0)
        memo = {}
        def cost(l, r):
            key = (l, r)
            if key in memo:
                return memo[key]
            length = r - l
            ones = prefix[r] - prefix[l]
            best = flatCost if ones == 0 else length * ones * encCost
            if length % 2 == 0:
                mid = (l + r) // 2
                best = min(best, cost(l, mid) + cost(mid, r))
            memo[key] = best
            return best
        return cost(0, n)

