var minCost = function(s, encCost, flatCost) {
    const n = s.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + (s[i] === '1' ? 1 : 0);
    const memo = new Map();
    function cost(l, r) {
        const key = l * (n + 1) + r;
        if (memo.has(key)) return memo.get(key);
        const length = r - l;
        const ones = prefix[r] - prefix[l];
        let best = ones === 0 ? flatCost : length * ones * encCost;
        if (length % 2 === 0) {
            const mid = (l + r) >> 1;
            best = Math.min(best, cost(l, mid) + cost(mid, r));
        }
        memo.set(key, best);
        return best;
    }
    return cost(0, n);
};
